# Generated by openai (gpt-5.2)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
  agent any

  parameters {
    string(name: 'REGISTRY_URL', defaultValue: 'registry.example.com', description: 'Docker registry hostname (and optional port), e.g. registry.example.com:5000')
    string(name: 'IMAGE_NAME', defaultValue: 'my-team/my-app', description: 'Image name/repository path within the registry, e.g. team/app')
    string(name: 'IMAGE_TAG', defaultValue: 'latest', description: 'Image tag to build and push, e.g. 1.2.3 or feature-branch')
    string(name: 'DOCKERFILE', defaultValue: 'Dockerfile', description: 'Path to Dockerfile')
    string(name: 'CONTEXT_DIR', defaultValue: '.', description: 'Docker build context directory')
    booleanParam(name: 'PUSH_IMAGE', defaultValue: true, description: 'Push image after build')
  }

  environment {
    FULL_IMAGE = "${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
  }

  stages {
    stage('Checkout') {
      steps {
        checkout scm
      }
    }

    stage('Build') {
      steps {
        sh '''
          set -euo pipefail
          echo "Building image: ${FULL_IMAGE}"
          docker build -f "${DOCKERFILE}" -t "${FULL_IMAGE}" "${CONTEXT_DIR}"
        '''
      }
    }

    stage('Push') {
      when {
        expression { return params.PUSH_IMAGE }
      }
      steps {
        sh '''
          set -euo pipefail
          echo "Pushing image: ${FULL_IMAGE}"
          docker push "${FULL_IMAGE}"
        '''
      }
    }
  }

  post {
    always {
      sh '''
        set +e
        docker image inspect "${FULL_IMAGE}" >/dev/null 2>&1 && docker rmi -f "${FULL_IMAGE}" >/dev/null 2>&1 || true
      '''
    }
  }
}